        /// <summary>
        /// Parse the embedded data into a list of polylines, where each polyline is a list of (lat, lon) in degrees.
        /// </summary>
        public static List<List<PointF>> GetPolylines()
        {
            var result = new List<List<PointF>>(PolylineCount);
            for (int i = 0; i < PolylineCount; i++)
            {
                int start = PolylineStart[i];
                int end = PolylineStart[i + 1];
                var polyline = new List<PointF>(end - start);
                for (int j = start; j < end; j++)
                {
                    float lat = Points[j, 0] / 100f;
                    float lon = Points[j, 1] / 100f;
                    polyline.Add(new PointF(lat, lon));
                }
                result.Add(polyline);
            }
            return result;
        }
    }
